mapper.select:
SELECT id, status
FROM t_article
WHERE id = #{id}
  AND deleted = 0
  AND status IN (2, 4)
  AND publish_at <= #{now}

mapper.update:
UPDATE t_article
SET comment_count = comment_count + #{delta}
WHERE id = #{id}
  AND deleted = 0
  AND comment_count + #{delta} >= 0

